    44→function renderMarkdown(text: string): string {
    45→  const lines = text.split("\n");
    46→  const out: string[] = [];
    47→  let inCode = false;
    48→  let inTable = false;
    49→
    50→  for (let i = 0; i < lines.length; i++) {
    51→    const line = lines[i];
    52→
    53→    if (line.startsWith("```")) {
    54→      if (inCode) {
    55→        out.push("</code></pre>");
    56→        inCode = false;
    57→      } else {
    58→        const lang = line.slice(3).trim();
    59→        out.push(`<pre class="bg-navy border border-silver/20 rounded-xl p-4 overflow-x-auto text-xs font-mono text-silver my-3"><code class="language-${lang}">`);
    60→        inCode = true;
    61→      }
    62→      continue;
    63→    }
    64→
    65→    if (inCode) {
    66→      out.push(escapeHtml(line));
    67→      continue;
    68→    }
    69→
    70→    if (line.startsWith("|")) {
    71→      if (!inTable) {
    72→        out.push('<div class="overflow-x-auto my-4"><table class="w-full text-xs border-collapse">');
    73→        inTable = true;
    74→      }
    75→      if (line.replace(/\|/g, "").trim().replace(/-/g, "").trim() === "") {
    76→        continue;
    77→      }
    78→      const cells = line.split("|").filter((_, i, a) => i > 0 && i < a.length - 1);
    79→      const isHeader = i + 1 < lines.length && lines[i + 1]?.includes("---");
    80→      if (isHeader) {
    81→        out.push(`<tr>${cells.map((c) => `<th class="text-left px-3 py-2 text-cool-steel uppercase tracking-wider border-b border-silver/15 font-bold text-[10px]">${inline(c.trim())}</th>`).join("")}</tr>`);
    82→      } else {
    83→        out.push(`<tr class="border-b border-white/3 hover:bg-deep-space/10">${cells.map((c) => `<td class="px-3 py-2 text-silver">${inline(c.trim())}</td>`).join("")}</tr>`);
    84→      }
    85→      continue;
    86→    } else if (inTable) {
    87→      out.push("</table></div>");
    88→      inTable = false;
    89→    }
    90→
    91→    if (line.startsWith("# ")) {
    92→      out.push(`<h1 class="text-2xl font-extrabold text-white mt-6 mb-3">${inline(line.slice(2))}</h1>`);
